import tkinter as tk
from tkinter import messagebox, filedialog
import base64
import os


window_width = 500
window_height = 340
load_file_bool = False


base64_string1 = ''

base64_string2 = ''


def cross_array_in_string(source, begin_cross, end_cross):
    array_cross = []
    item = begin_cross
    while item <= end_cross:
        array_cross.append(chr(source[item]))
        item += 1
    new_array_cross = array_cross[::2]
    result_string = ''.join(new_array_cross)

    return result_string


def open_file():
    global load_file_bool, file_name_out, array_source
    file_path = filedialog.askopenfilename()
    file_name_in = os.path.basename(file_path)
    with open(file_path, 'rb') as file:
        file.seek(0, 2)
        file_length = file.tell()
    file_extension = os.path.splitext(file_name_in)[1]
    file_name_out = file_name_in.replace(".bin", "_fix.bin")
    if file_length != 512 or file_extension != '.bin':
        messagebox.showinfo('Ошибка', 'Неверный формат выбранного файла')
        load_file_bool = False
    else:
        with open(file_path, 'rb') as file:
            array_source = file.read()
        load_file_bool = True
        label = tk.Label(root, text='Исходный файл')
        label.place(x=393, y=67)
        date_replace = cross_array_in_string(array_source, 144, 158)
        label = tk.Label(root, text='Дата замены:\n' + date_replace)
        label.place(x=400, y=85)
        serial_namber = cross_array_in_string(array_source, 88, 110)
        label = tk.Label(root, text='Серийный номер:\n' + serial_namber)
        label.place(x=390, y=120)
        total_summ = hex(array_source[162])[2:] + hex(array_source[160])[2:]
        total_summ = total_summ.upper()
        label = tk.Label(root, text='Контрольная\n сумма:\n' + total_summ)
        label.place(x=400, y=155)


def summ_list(list, size):
    summ_block = 0
    for byte in list:
        summ_block += int(hex(byte), 16)

    return summ_block


def symbol_array(symbol):
    symbol_list = []
    for index, char in enumerate(symbol):
        symbol_list.append(ord(char))
        if index < len(symbol) - 1:
            symbol_list.append(0)

    return symbol_list


def array_numbers(number, size):
    array_number = [number] * size

    return array_number


def save_file():
    date_input = entry_date.get()
    serial_input = entry_serial.get()
    if not load_file_bool:
        messagebox.showinfo(
            'Ошибка',
            'Исходный файл EPROM не загружен.\nЗагрузите исходный файл EPROM!')
    elif len(date_input) != 8 and len(serial_input) != 12:
        messagebox.showinfo(
            'Ошибка', 'Неправильно введена дата и серийный номер')
    elif len(date_input) != 8:
        messagebox.showinfo('Ошибка', 'Неправильно введена дата')
    elif len(serial_input) != 12:
        messagebox.showinfo('Ошибка', 'Неправильно введен серийный номер')
    else:
        array_block = [0] * 88
        for byte in range(88):
            array_block[byte] = array_source[byte]
        retblock_array = array_block + symbol_array(
            serial_input) + array_numbers(0, 9) + symbol_array(
            'SYBT5') + array_numbers(0, 15) + symbol_array(
            date_input) + array_numbers(0, 1)
        total = summ_list(retblock_array, 160)
        sumarray = retblock_array + array_numbers(
            int(hex(total)[4:6], 16), 1) + array_numbers(
            0, 1) + array_numbers(
            int(hex(total)[2:4], 16), 1) + array_numbers(0, 349)
        file_path = filedialog.asksaveasfilename(initialfile=file_name_out)
        if file_path:
            with open(file_path, 'wb') as file:
                file.write(bytearray(sumarray))
            messagebox.showinfo(
                'Сохранение файла',
                f'Сохранен файл: {file_name_out}\n\n'
                f'с серийным номером: {serial_input}\n\n'
                f'и датой замены: {date_input}')


def validate_input_date(char, value):
    if len(value) < 9 and (char.isdigit() or char == '/'):
        return True

    return False


def validate_input_serial(char, value):
    if len(value) < 13 and (char.isdigit() or char.isalpha()):
        return True

    return False


def put_decode_image(base64_string, x_axis, y_axis):
    image_data = base64.b64decode(base64_string)
    image = tk.PhotoImage(data=image_data)
    label_image = tk.Label(root, image=image)
    label_image.image = image
    label_image.place(x=x_axis, y=y_axis)


root = tk.Tk()
root.title('Обновление EPROM SYBT5')

root.geometry(f'{window_width}x{window_height}')
root.resizable(False, False)

put_decode_image(base64_string1, 10, 1)
put_decode_image(base64_string2, window_width - 110, 1)


button_open = tk.Button(
    root, text='Загрузить исходный файл EPROM', command=open_file)
button_open.pack(pady=30)

label_date = tk.Label(
    root, text='Введите дату замены батарей\n в формате месяц/день/год')
label_date.pack(pady=1)

vcmd = (root.register(validate_input_date), '%S', '%P')
entry_date = tk.Entry(root, width=8, validate='key', validatecommand=vcmd)
entry_date.pack(pady=10)

label_serial = tk.Label(root, text='Введите двенадцатизначный серийный\n'
                        'номер, например: QS1225387492')
label_serial.pack(pady=10)

vcmd = (root.register(validate_input_serial), '%S', '%P')
entry_serial = tk.Entry(root, width=13, validate='key', validatecommand=vcmd)
entry_serial.pack(pady=1)

button_save = tk.Button(
    root, text='Сохранить итоговый файл EPROM', command=save_file)
button_save.pack(pady=30)

root.mainloop()
